import { SpatialDb } from "autk-db";
import { AutkMap, LayerType, ColorMapInterpolator } from "autk-map";

function setPhase(text: string) {
  const el = document.getElementById("phase");
  if (el) el.textContent = text;
  console.log(`[Phase] ${text}`);
}

async function main() {
  const canvas = document.getElementById("map-canvas") as HTMLCanvasElement;

  // ── 1. Initialize spatial database ──
  setPhase("Initializing spatial database...");
  const db = new SpatialDb();
  await db.init();
  console.log("SpatialDb initialized");

  // ── 2. Load OSM data for Manhattan Island ──
  setPhase("Loading OSM data for Manhattan Island...");
  console.log("Fetching Overpass API for Manhattan Island...");

  await db.loadOsmFromOverpassApi({
    queryArea: {
      geocodeArea: "New York",
      areas: ["Manhattan Island"],
    },
    outputTableName: "osm",
    autoLoadLayers: {
      coordinateFormat: "EPSG:3395",
      layers: ["surface", "parks", "water", "roads", "buildings"],
      dropOsmTable: true,
    },
    onProgress: (phase: string) => {
      setPhase(`OSM: ${phase}`);
      console.log(`Overpass progress: ${phase}`);
    },
  });

  console.log("OSM data loaded successfully");

  // Log layer info
  const layerTables = db.getLayerTables();
  console.log(`Loaded ${layerTables.length} OSM layers:`, layerTables.map((l) => l.name));

  // ── 3. Load subway station CSV ──
  setPhase("Loading subway station data...");
  console.log("Loading subway CSV from /data/subway_manhattan_clean.csv");

  await db.loadCsv({
    csvFileUrl: "http://localhost:3005/data/subway_manhattan_clean.csv",
    outputTableName: "subway_stations",
    delimiter: ",",
    geometryColumns: {
      latColumnName: "latitude",
      longColumnName: "longitude",
      coordinateFormat: "EPSG:3395",
    },
  });

  const stationData = await db.getTableData({ tableName: "subway_stations" });
  console.log(`Subway stations loaded: ${stationData.length} stations`);

  // ── 4. Spatial join: count subway stations within 500m of each building ──
  setPhase("Spatial join: counting subway stations within 500m of each building...");
  console.log("Spatial join started...");

  await db.spatialJoin({
    tableRootName: "osm_buildings",
    tableJoinName: "subway_stations",
    output: { type: "MODIFY_ROOT" },
    spatialPredicate: "NEAR",
    joinType: "LEFT",
    nearDistance: 500,
    nearUseCentroid: true,
    groupBy: {
      selectColumns: [
        {
          tableName: "subway_stations",
          column: "key",
          aggregateFn: "count",
          aggregateFnResultColumnName: "subway_count",
          normalize: false,
        },
      ],
    },
  });

  console.log("Spatial join complete");

  // Get the enriched buildings layer
  const buildingsGeojson = await db.getLayer("osm_buildings");
  console.log(
    `Buildings with subway data: ${buildingsGeojson.features.length} features`
  );

  // Log some stats about subway counts
  const counts = buildingsGeojson.features.map(
    (f) => f.properties?.sjoin?.count?.subway_count ?? 0
  );
  const maxCount = Math.max(...counts);
  const avgCount = counts.reduce((a: number, b: number) => a + b, 0) / counts.length;
  console.log(`Subway count stats — max: ${maxCount}, avg: ${avgCount.toFixed(2)}`);

  // ── 5. Initialize map renderer ──
  setPhase("Initializing 3D map renderer...");
  console.log("Initializing AutkMap...");

  const map = new AutkMap(canvas);
  await map.init();
  console.log("AutkMap initialized");

  // ── 6. Load all OSM layers onto the map ──
  setPhase("Loading layers onto map...");

  const layerTypeMap: Record<string, LayerType> = {
    osm_surface: LayerType.AUTK_OSM_SURFACE,
    osm_parks: LayerType.AUTK_OSM_PARKS,
    osm_water: LayerType.AUTK_OSM_WATER,
    osm_roads: LayerType.AUTK_OSM_ROADS,
    osm_buildings: LayerType.AUTK_OSM_BUILDINGS,
  };

  for (const layer of layerTables) {
    const geojson = layer.name === "osm_buildings"
      ? buildingsGeojson
      : await db.getLayer(layer.name);
    const type = layerTypeMap[layer.name] ?? (layer.type as LayerType);
    map.loadGeoJsonLayer(layer.name, geojson, type);
    console.log(`Layer "${layer.name}" loaded (${geojson.features.length} features)`);
  }

  // ── 7. Apply thematic coloring to buildings ──
  setPhase("Applying subway accessibility coloring...");
  console.log("Applying thematic coloring based on subway station count...");

  map.updateRenderInfoProperty(
    "osm_buildings",
    "colorMapInterpolator",
    ColorMapInterpolator.SEQUENTIAL_REDS
  );
  map.updateRenderInfoProperty("osm_buildings", "isColorMap", true);
  map.updateRenderInfoProperty(
    "osm_buildings",
    "colorMapLabels",
    ["0 stations", `${maxCount} stations`]
  );

  map.updateGeoJsonLayerThematic(
    "osm_buildings",
    buildingsGeojson,
    (feature) => feature.properties?.sjoin?.count?.subway_count ?? 0,
    true
  );

  console.log("Thematic coloring applied successfully");

  // ── 8. Start rendering ──
  map.draw();
  console.log("Scene rendered with all layers");

  // Hide loading overlay
  const loadingEl = document.getElementById("loading");
  if (loadingEl) loadingEl.style.display = "none";

  setPhase("Done");
  console.log("Application fully loaded and rendering");
}

main().catch((err) => {
  console.error("Application error:", err);
  setPhase(`Error: ${err.message}`);
});

# Computing into Properties

`computeFunctionIntoProperties` runs a WGSL shader function over every feature in a GeoJSON and writes the result to `feature.properties.compute[outputColumnName]`.

## Minimal Example

Multiply two scalar properties for each feature:

```typescript
import { geojsonCompute } from 'autk-compute';

const result = await geojsonCompute.computeFunctionIntoProperties({
  geojson: myFeatureCollection,
  variableMapping: {
    area: 'properties.area',       // WGSL variable ← GeoJSON property path
    floors: 'properties.floors',
  },
  outputColumnName: 'volume',
  wglsFunction: 'return area * floors;',
});

// result is a new FeatureCollection
// result.features[i].properties.compute.volume === area * floors
```

## Variable Mapping

`variableMapping` maps WGSL variable names to property paths in each feature. Paths use dot notation:

```typescript
variableMapping: {
  x: 'properties.longitude',
  y: 'properties.latitude',
  pop: 'properties.population',
}
```

All mapped variables are passed as `f32` to the WGSL function.

## Array Variables

Declare array variables with a fixed length. All features must have arrays of this length (shorter arrays are zero-padded):

```typescript
variableMapping: {
  score: 'properties.score',
  weights: 'properties.weights', // array property
},
arrayVariables: {
  weights: 5, // length = 5
},
wglsFunction: `
  var total = 0.0;
  for (var i = 0u; i < weights_length; i++) {
    total += weights[i];
  }
  return score * total;
`,
```

Inside WGSL, an array named `weights` is available as `array<f32, 5>`, and `weights_length` is a `u32`.

## Matrix Variables

Declare matrix variables with explicit row/column dimensions. Matrices are passed as a flattened row-major array:

```typescript
variableMapping: {
  mat: 'properties.transform_matrix',
},
matrixVariables: {
  mat: { rows: 3, cols: 3 },
},
wglsFunction: `
  // Sum the diagonal (trace)
  var trace = 0.0;
  for (var i = 0u; i < mat_rows; i++) {
    trace += mat[i * mat_cols + i];
  }
  return trace;
`,
```

## The WGSL Function

The function body must return a single `f32` value. It has access to all declared variables as parameters. No imports or additional boilerplate needed — just write the body:

```typescript
wglsFunction: 'return x + y * 2.0;'
```

:::tip WGSL types
All scalar inputs are `f32`. Array inputs are `array<f32, N>`. Matrix inputs are `array<f32, rows*cols>`. Your return value is always `f32`.
:::

# Patterns

## Compute → Update Table → Thematic Map

The most common pattern: compute a new value per feature, write it back to the database, then color the map layer by it.

```typescript
import { geojsonCompute } from 'autk-compute';
import { ColorMapInterpolator, LayerType } from 'autk-map';

// 1. Get the current layer data from autk-db
const geojson = await db.getLayer('buildings');

// 2. Compute a new property via GPU
const enriched = await geojsonCompute.computeFunctionIntoProperties({
  geojson,
  variableMapping: {
    area: 'properties.area',
    floors: 'properties.floors',
  },
  outputColumnName: 'volume',
  wglsFunction: 'return area * floors;',
});

// 3. Write the result back to autk-db
await db.updateTable({
  tableName: 'buildings',
  data: enriched,
  strategy: 'replace',
});

// 4. Refresh the map layer with thematic coloring
const updated = await db.getLayer('buildings');
map.updateRenderInfoProperty('buildings', 'colorMapInterpolator', ColorMapInterpolator.SEQUENTIAL_BLUES);
map.updateRenderInfoProperty('buildings', 'isColorMap', true);
map.updateGeoJsonLayerThematic(
  'buildings',
  updated,
  (f) => f.properties?.compute?.volume ?? 0,
  true
);
```

## Performance Notes

- `autk-compute` launches one GPU workgroup per feature. The overhead of GPU dispatch dominates for very small datasets (< ~500 features). For those cases, plain JavaScript is faster.
- All features must have the same property schema. Missing values default to `0`.
- The returned `FeatureCollection` is a new object; the original `geojson` is not mutated.

